(function(){
  var la = window.LEXICON_AUGMENT || {};
  var nestedManual = la.manualParadigms || {};
  var manual = window.MANUAL_PARADIGMS || (window.MANUAL_PARADIGMS = {});
  var strict = window.STRICT_AUDIT || (window.STRICT_AUDIT = { lemmas: {} });
  var updated = [];

  function countKinds(forms){
    var finite = 0, infinitives = 0, participles = 0;
    (forms || []).forEach(function(f){
      if (!f || !f.kind) return;
      if (f.kind === 'finite') finite += 1;
      else if (f.kind === 'infinitive') infinitives += 1;
      else if (f.kind === 'participle') participles += 1;
    });
    return { finite: finite, infinitives: infinitives, participles: participles, total: finite + infinitives + participles };
  }

  Object.keys(nestedManual).forEach(function(lemma){
    var incoming = nestedManual[lemma];
    var existing = manual[lemma];
    if (!existing || (incoming && incoming.length > existing.length)) {
      manual[lemma] = incoming;
      updated.push(lemma);
    }
  });

  updated.forEach(function(lemma){
    var counts = countKinds(manual[lemma]);
    strict.lemmas[lemma] = {
      lemma: lemma,
      status: 'manual',
      readiness: 'advanced',
      manualForms: counts.total,
      finite: counts.finite,
      infinitives: counts.infinitives,
      participles: counts.participles,
      slotChecks: (strict.lemmas[lemma] && strict.lemmas[lemma].slotChecks) || 0,
      curated: true,
      needsAudit: false,
      summary: 'manual · forms ' + counts.total + ' · slot checks ' + (((strict.lemmas[lemma] && strict.lemmas[lemma].slotChecks) || 0))
    };
  });

  window.MANUAL_PARADIGMS = manual;
  window.STRICT_AUDIT = strict;
  window.__AGVL_COMPLETION_PATCH__ = {
    activatedManualParadigms: updated,
    timestamp: '2026-03-28'
  };
})();


